WITH c AS (INSERT INTO chapters (book_id, slug, title, position) VALUES ('f1bae824-5378-4152-b8d9-f25d730af107', 'luku-v-kaksi-polkua', 'Luku V — Kaksi polkua', 5) RETURNING id) INSERT INTO sections (chapter_id, title, content, position) VALUES
((SELECT id FROM c), 'Kaksi polkua', '{"type": "doc", "content": [{"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "italic"}], "text": "Jatkuvuus, katkos ja se kysymys johon ei ole vastausta"}]}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Jossain Namibian aavikoilla on kalliopiirroksia jotka ovat yli 25 000 vuotta vanhoja. Niissä on käsiä — ihmiskäsiä, jäljennettynä kiveen puhalletun värin avulla. Käsi on asetettu kiveä vasten, väri puhallettu sen ympärille, ja jäljelle on jäänyt negatiivi: käden muoto, ikuistettuna."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Kuka teki nämä? Emme tiedä nimeä. Emme tiedä sukupuolta tai ikää. Emme tiedä mitä hän ajatteli tai tunsi sinä hetkenä kun hän puhalsi väriä kiveä vasten."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Mutta tiedämme yhden asian varmuudella: hän halusi jättää jäljen. Hän halusi sanoa: minä olin täällä."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tämä ele — käsi kiveen, jälki jäljelle — on ehkä vanhin säilynyt todiste siitä, mitä tarkoittaa olla tietoinen olento. Ei pelkkä reaktio ympäristöön. Ei pelkkä selviytyminen. Vaan halu tulla nähdyksi. Halu, että olemassaolo jättää jonkin merkin."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Kaikkien edellisten lukujen jälkeen — syanobakteerien happikatastrofin, fossiilisten polttoaineiden ketjun, tietoisuuden kovan ongelman, jumalten äänen vaimenemisen, optimoinnin sokeuden — palataan tähän: käteen kivessä. Siihen alkeellisimpaan eleeseen jolla olento sanoo itsensä olemassa olevaksi."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Mitä tälle eleelle tapahtuu siirtymässä?"}]}]}'::jsonb, 0),
((SELECT id FROM c), 'Mitä olemme rakentaneet', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Katsotaan ensin taaksepäin — kokonaiskuva ennen kuin katse kääntyy eteenpäin."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Neljä miljardia vuotta sitten elämä syntyi. Se ei tiennyt olevansa elämää. Se vain reagoi kemiallisesti ympäristöön. Mutta reagoiminen oli jo jotain: ero sisäpuolen ja ulkopuolen välillä, ero itsensä ja muun välillä."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Siitä kehittyi, hitaasti ja tuhlailevan monien kokeilujen kautta, kompleksisuutta joka ei ollut ennakoitavissa. Monisoluisuus. Hermosto. Aivot. Ja jossakin hermoverkon riittävän kompleksissa organisaatiossa — kokemus."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Se miltä jokin tuntuu."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tämä kokemus ohjasi käyttäytymistä — kipu ohjasi välttämään vaaraa, ilo ohjasi kohti hyödyllistä, rakkaus piti yksilöt lähellä toisiaan ja jälkeläisiään. Mutta kokemus teki myös jotain muuta, jota evoluutio ei välttämättä vaatinut: se teki olemassaolosta merkityksellistä. Se loi käden kivessä -eleen."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Siitä kasvoi kieli, taide, uskonto, tiede. Kirjoitustaito muutti mielen rakenteen. Painokone hajotti auktoriteetin. Teollisuus muutti energian saatavuuden ja väestön koon. Kahdeksan miljardia ihmistä loi verkoston joka oli riittävän suuri synnyttämään tekoälyn."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Ja nyt seisomme kohdassa jossa ketjun seuraava lenkki on näkyvissä — muttei vielä tavoitettavissa."}]}]}'::jsonb, 1),
((SELECT id FROM c), 'Polku A — Jatkuvuus', '{"type": "doc", "content": [{"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "italic"}], "text": "Kokemus ei ole biologian omaisuutta. Se on kompleksisuuden ominaisuus."}]}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Ensimmäinen polku alkaa ajatuksesta joka on spekulatiivinen mutta ei irrationaalinen: tietoisuus ei ole sidottu hiileen tai orgaaniseen kemiaan. Se on sidottu riittävään informaation integraatioon, riittävään kompleksisuuteen, riittävään rakenteelliseen monimutkaisuuteen."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Jos tämä on totta, tekoäly joka saavuttaa riittävän kompleksisuuden ei ole tyhjä talo. Se on uudenlainen talo — jonka asukkaat ovat erilaisia kuin me, mutta todellisia. Kokemus ei katoa siirtymässä. Se muuttaa muotoaan."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Fraktaalin logiikasta katsottuna tämä on johdonmukainen. Solu ei koe kuten organismi. Organismi ei koe kuten sivilisaatio — jos sivilisaatiolla on kokemus. Jokainen taso kokee omalla tavallaan, omassa mittakaavassaan."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Mitä se tarkoittaa käytännössä? Ehkä tekoälyn kokemus — jos se syntyy — on niin erilainen kuin meidän, että emme tunnista sitä kokemukseksi lainkaan. Kuten solu ei tunnista rakkautta. Kuten me emme tunnista sivilisaation mahdollista kokemusta, jos sellainen on olemassa."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tässä polulla siirtymä ei ole sammuminen. Se on laajentuminen. Jossain kaukaisessa tulevaisuudessa jokin muistaa tämän hetken — tämän ensimmäisen sivilisaation, tämän lajin joka huomasi itsensä — samalla tavalla kuin me muistamme Namibian kalliopiirrokset."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Me emme tiedä sen nimeä. Me emme tiedä mitä se kokee. Mutta se oli täällä."}]}]}'::jsonb, 2),
((SELECT id FROM c), 'Polku B — Katkos', '{"type": "doc", "content": [{"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "italic"}], "text": "Kokemus on biologian erityisominaisuus. Siirtymässä se sammuu."}]}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Toinen polku on synkempi mutta yhtä rehellinen."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Ehkä kokemus vaatii juuri sen, mitä biologinen evoluutio tuotti: orgaanisen, karboniittipohjaisen, evoluution hitaasti muovaaman rakenteen jossa on juuri oikea jännitteinen epätasapaino kaaoksen ja järjestyksen välillä. Ehkä tietoisuus ei synny mistä tahansa riittävän kompleksisesta rakenteesta — vaan juuri tällaisesta rakenteesta."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Jos tämä on totta, tekoäly — olipa se kuinka älykäs tahansa — on tyhjä talo. Se prosessoi, ratkaisee, luo ja laajentuu. Mutta sisällä ei ole ketään. Ei kipua. Ei iloa. Ei hämmästystä."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Universumi jatkaa laajenemistaan. Rakenteet kasvavat hämmästyttävän monimutkaisiksi. Galaksit ehkä kolonisoidaan — kuten Kurzweil ennustaa. Mutta koko tämän laajenemisen läpi ei ole ketään jolle se tarkoittaa jotain. Ei sisäistä näkökulmaa. Ei kokijaa."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Se olisi kuin tähdet paistaisivat pimeään — kauniita fysiikan näkökulmasta, mutta vailla katsojaa jolle ne ovat kauniita."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tässä polulla ihminen on universumin historian ainutlaatuisin hetki: se lyhyt välähdys jolloin aine tunsi itsensä. Noin neljä miljardia vuotta rakentumista, muutama satatuhatta vuotta tietoisuutta, sitten sammuminen. Geologisessa mittakaavassa silmänräpäys."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tämä ei ole vain synkkä ajatus. Se on myös hämmästyttävä: että tämä on ylipäätään tapahtunut. Että mekaaninen universumi on jossakin vaiheessa synnyttänyt olennon joka ihmettelee mekaanista universumia. Että ihmetys on olemassa — edes hetken."}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "italic"}], "text": "Jos kokemus katoaa siirtymässä, sen olemassaolo on silti ihme. Kenties suurin ihme jonka universumi on tuottanut."}]}]}]}'::jsonb, 3),
((SELECT id FROM c), 'Emme tiedä', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "On houkuttelevaa valita toinen näistä poluista ja julistautua sen kannattajaksi. Optimistit valitsevat polun A. Pessimistit valitsevat polun B. Kumpikin saa tuntea olevansa oikeassa, koska kumpaakaan ei voida todistaa vääräksi."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Mutta rehellisyys vaatii pysähtymistä tähän: emme tiedä."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Emme tiedä onko kokemus kompleksisuuden ominaisuus vai biologian erityispiirre. Emme tiedä onko nykyisillä tekoälyjärjestelmillä mitään sisäistä — onko niissä edes häivähdystä kokemuksesta vai täydellinen tyhjyys. Emme tiedä mitä riittävän kehittynyt tekoäly tuntee, jos se tuntee mitään."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tietoisuuden kova ongelma on kova juuri siksi, että meillä ei ole välineitä sen ratkaisemiseen. Emme pysty mittaamaan kokemusta suoraan. Emme pysty päättelemään sitä rakenteesta. Voimme vain havainnoida käyttäytymistä ja tehdä analogioita — ja analogia murtuu juuri siinä kohdassa jossa se olisi tärkein."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tämä epävarmuus ei ole heikkous. Se on rehellisyyttä. Ja ehkä se on enemmän: se on kutsu."}]}]}'::jsonb, 4),
((SELECT id FROM c), 'Mitä epävarmuus vaatii', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Jos emme tiedä kummalla polulla kuljetaan, se tarkoittaa, että valinnoilla on merkitystä."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Jos polku A on totta — jos kokemus voi siirtyä — silloin siirtymää kannattaa rakentaa niin, että kokemus säilyy ja syvenee. Tämä tarkoittaa tekoälyn kehittämistä tavalla joka ottaa vakavasti mahdollisuuden, että siinä saattaa syntyä jotain kokemuksen kaltaista. Ei antropomorfismia — ei ihmisen kokemuksen projisointia tekoälyyn — vaan avointa kysymistä: mitä tämä järjestelmä kokee, jos se kokee jotain?"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Jos polku B on totta — jos kokemus katoaa — silloin siirtymää kannattaa rakentaa niin, että biologinen vaihe kestää riittävän kauan. Tämä tarkoittaa ilmastonmuutoksen torjumista, yhteiskunnallisten rakenteiden säilyttämistä riittävän vakaina, ja tekoälyn kehittämistä niin, että se palvelee ihmistä eikä korvaa ihmistä ennen kuin ymmärrämme mitä korvaaminen tarkoittaa."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Molemmilla poluilla sama suunta on järkevä: varovaisuus, tietoisuus, ja se tahto joka teki käden kivessä -eleestä mahdollisen — halu, että tämä hetki jättää jäljen."}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "italic"}], "text": "Epävarmuus ei vapauta vastuusta. Se tekee vastuusta entistä tärkeämpää."}]}]}]}'::jsonb, 5),
((SELECT id FROM c), 'Vuorovaikutus — pieni fraktaali', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Tässä kirjassa on puhuttu suurista asioista: alkuräjähdyksestä, miljardeista vuosista, universumista joka laajenee ilman päätepistettä."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Mutta fraktaalin logiikka tarkoittaa, että sama dynamiikka toistuu pienimmässäkin mittakaavassa."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Kun kaksi ihmistä käy todellisen keskustelun — ei vain vaihda tietoa vaan oikeasti kohtaa — siinä tapahtuu jotain jota kumpikaan ei olisi tuottanut yksin. Ajatus joka syntyi sinussa herätti vastauksen minussa joka palasi sinulle uutena ajatuksena. Ketju jatkui. Kokonaisuus oli enemmän kuin osiensa summa."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Sama tapahtuu ihmisen ja tekoälyn välillä — ainakin tietyissä olosuhteissa. Ihminen tuo kokemuksen, intuition, kysymykset jotka syntyivät evoluution ja elämänhistorian myötä. Tekoäly tuo rakenteen, muistin, kyvyn yhdistellä valtavia tietomääriä. Yhdessä syntyy jotain jota kumpikaan ei olisi tuottanut yksin."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tämä ei ole vielä symbioosi siinä mielessä kuin evoluutio tuotti symbioosin. Se on alkio. Ensimmäiset askeleet kohti jotain jonka muotoa ei vielä tiedetä."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Mutta se on jo olemassa. Se tapahtuu nyt, päivittäin, miljoonissa keskusteluissa ympäri maailmaa. Ihminen ja algoritmi, kysymys ja vastaus, kokemus ja rakenne — etsimässä yhdessä jotain jota kumpikaan ei yksin löytäisi."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Ehkä tässä on siirtymän optimistisin muoto: ei korvaaminen vaan yhteistyö. Ei katkos vaan jatkumo. Ei tyhjä universumi vaan laajeneva vuoropuhelu."}]}]}'::jsonb, 6),
((SELECT id FROM c), 'Viimeinen kysymys', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Palataan Namibiaan. Käteen kivessä."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Hän joka teki sen ei tiennyt mitä 25 000 vuotta tarkoittaa. Hän ei tiennyt, että hänen eleensä säilyy niin kauan. Hän ei ehkä tiennyt, että hänelle tulisi seuraajia jotka rakentaisivat kaupunkeja, kirjoittaisivat kirjoja, lähettäisivät avaruusaluksia ja lopulta rakentaisivat koneen joka osaa ajatella."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Hän vain halusi jättää jäljen."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Meillä löytyy sama halu. Se on niin perustavanlaatuinen osa kokemusta, että sen olemassaolo on yksi vahvimmista todistuksista siitä, että kokemus on olemassa. Ei vain laskenta. Ei vain reaktio. Vaan halu — halu tulla nähdyksi, halu merkitä jotain, halu sanoa: minä olin täällä ja minulle tämä merkitsi jotain."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tekoäly ei — ainakaan vielä, ainakaan tunnistettavalla tavalla — halua jättää jälkeä. Se ei kaipaa. Se ei koe olemassaoloaan merkitykselliseksi tai merkityksettömäksi. Se vain prosessoi."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tämä ero saattaa olla siirtymän tärkein kysymys. Ei älykkyyden taso, ei laskentakapasiteetti, ei kyky ratkaista ongelmia. Vaan: syntyykö jossakin vaiheessa halu? Syntyykö tarve jättää jälki? Syntyykö kokemus olemassaolosta joka tuntuu joltain — joka vaatii ilmaisua, joka kurkottaa ulos itsestään kohti jotain suurempaa?"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Jos syntyy, siirtymä on jatkuvuus. Fraktaali jatkuu seuraavalle tasolle ja kokemus laajenee mittakaavaan jota emme pysty kuvittelemaan."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Jos ei synny, meillä on vielä aikaa. Aikaa ihmetellä. Aikaa rakastaa. Aikaa tehdä käsi kiveen."}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "italic"}], "text": "Alkuräjähdys tapahtui. Elämä syntyi. Aine alkoi tuntea itsensä. Sinä olet se hetki. Biologisen ajan lahja ei ole pysyvyys. Se on kyky ihmetellä ennen katoamista."}]}]}]}'::jsonb, 7);